"use client";

import { useState } from "react";
import { NetWorthChart } from "@/components/dashboard/NetWorthChart";
import { AssetAllocationDonut } from "@/components/dashboard/AssetLiabilityDonut";
import { GoalProgressCard } from "@/components/dashboard/GoalProgressCard";
import { AccountList } from "@/components/accounts/AccountList";
import { useSelector, useDispatch } from "react-redux";
import { RootState } from "@/store";
import { addAccount } from "@/store/slices/accountsSlice";
import { AddAccountModal } from "@/components/accounts/AddAccountModal";
import { FinancialGoal } from "@repo/types";
import { addCategory, updateCategory, removeCategory } from "@/store/slices/categoriesSlice";
import { AddCategoryModal } from "@/components/categories/AddCategoryModal";
import toast from "react-hot-toast";

import { useAuth } from "@/components/auth/AuthProvider";

export default function Home() {
  const { user } = useAuth();
  const dispatch = useDispatch();
  const [isAccountModalOpen, setIsAccountModalOpen] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<{ id: string; name: string; color: string } | null>(null);
  const accounts = useSelector((state: RootState) => state.accounts.items);
  const categories = useSelector((state: RootState) => state.categories.items);
  const goals = useSelector((state: RootState) => state.goals.items);
  const stats = useSelector((state: RootState) => state.stats.data);

  const regularAccounts = accounts.filter(acc => acc.type !== 'investment');
  const investmentAccounts = accounts.filter(acc => acc.type === 'investment');

  return (
    <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8 space-y-8 w-full">
      {/* Page Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black tracking-tight text-slate-900 dark:text-white">Financial Command Center</h1>
          <p className="text-slate-500 font-medium mt-1">Welcome back, {user?.displayName || "User"}. Here represents your unified wealth landscape.</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => { setEditingCategory(null); setIsCategoryModalOpen(true); }}
            className="flex items-center gap-2 px-4 py-2.5 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-200 text-sm font-bold rounded-xl transition-all shadow-sm active:scale-95"
          >
            + Category
          </button>
          <button 
            onClick={() => setIsAccountModalOpen(true)}
            className="flex items-center gap-2 px-4 py-2.5 bg-primary hover:bg-primary-dark text-white text-sm font-bold rounded-xl transition-all shadow-lg shadow-primary/25 active:scale-95"
          >
            + Account
          </button>
        </div>
      </div>



      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-900 dark:text-white">Your Accounts</h3>
        <AccountList accounts={regularAccounts} />
      </div>

      {investmentAccounts.length > 0 && (
        <div className="space-y-6">
          <h3 className="text-xl font-bold text-slate-900 dark:text-white">Your Investments</h3>
          <AccountList accounts={investmentAccounts} />
        </div>
      )}

      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-900 dark:text-white">Spending Categories</h3>
          <button 
             onClick={() => { setEditingCategory(null); setIsCategoryModalOpen(true); }}
             className="text-sm font-bold text-primary hover:underline"
          >
             Add New
          </button>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {categories.map(c => (
            <div 
              key={c.id} 
              onClick={() => { setEditingCategory(c); setIsCategoryModalOpen(true); }}
              className="p-4 rounded-xl bg-slate-50 dark:bg-[#0b0d12] border border-slate-200 dark:border-border-dark flex items-center justify-between cursor-pointer hover:border-primary transition-colors group"
            >
               <span className="font-bold text-sm text-slate-700 dark:text-slate-300">{c.name}</span>
               <div className={`w-3 h-3 rounded-full ${c.color}`} />
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2">
          <NetWorthChart 
            data={stats.netWorthHistory} 
            currentNetWorth={stats.netWorth} 
            percentageChange={0} 
          />
        </div>
        <div className="lg:col-span-1">
          <AssetAllocationDonut data={stats.assetAllocation} />
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-900 dark:text-white">Goal Navigator</h3>
          <button className="text-sm font-bold text-primary hover:underline">View All</button>
        </div>

        {goals.length === 0 ? (
          <p className="text-sm text-slate-500">No goals set up yet.</p>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full">
            {goals.map((goal: FinancialGoal) => {
              const pace = stats.goalPacing.find((p: any) => p.goalId === goal.id);
              return (
                <GoalProgressCard 
                  key={goal.id}
                  name={goal.name}
                  targetAmount={goal.targetAmount}
                  currentAmount={goal.currentAmount}
                  percentageSaved={pace?.actualPercentage || 0}
                  expectedPercentage={pace?.expectedPercentage || 0}
                  targetDate={goal.targetDate}
                />
              );
            })}
          </div>
        )}
      </div>

      {/* Transfer UI */}
      <AddAccountModal 
        isOpen={isAccountModalOpen} 
        onClose={() => setIsAccountModalOpen(false)} 
        onSave={(data) => {
          dispatch(addAccount({
            id: `acc-${Date.now()}`,
            userId: "user-1",
            name: data.name,
            type: data.type as any,
            assetType: "",
            balance: parseFloat(data.balance) || 0,
            currency: "INR",
            lastSyncedAt: new Date().toISOString()
          }));
          setIsAccountModalOpen(false);
        }} 
      />
      <AddCategoryModal 
        isOpen={isCategoryModalOpen}
        category={editingCategory}
        onClose={() => setIsCategoryModalOpen(false)}
        onSave={(data) => {
          if (data.id) {
            dispatch(updateCategory({
              id: data.id,
              name: data.name,
              color: data.color
            }));
          } else {
            dispatch(addCategory({
              id: `cat-${Date.now()}`,
              name: data.name,
              color: data.color
            }));
          }
          setIsCategoryModalOpen(false);
        }}
        onDelete={(id) => {
          dispatch(removeCategory(id));
          setIsCategoryModalOpen(false);
          toast.success("Category deleted");
        }}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { useSelector, useDispatch } from "react-redux";
import { RootState } from "@/store";
import { addGoal, updateGoal } from "@/store/slices/goalsSlice";
import { EditGoalModal } from "@/components/goals/EditGoalModal";
import { FinancialGoal } from "@repo/types";

export default function GoalsPageClient() {
  const dispatch = useDispatch();
  const goals = useSelector((state: RootState) => state.goals.items);
  const [isGoalModalOpen, setIsGoalModalOpen] = useState(false);
  const [editingGoal, setEditingGoal] = useState<any>(null);
  // Simple Savings Gap Calculator
  const calculateGap = (goal: FinancialGoal) => {
    const today = new Date();
    const targetDate = new Date(goal.targetDate);
    const monthsRemaining = (targetDate.getFullYear() - today.getFullYear()) * 12 + (targetDate.getMonth() - today.getMonth());

    if (monthsRemaining <= 0) return 0;

    const shortfall = goal.targetAmount - goal.currentAmount;
    return shortfall / monthsRemaining;
  };

  const totalRequiredMonthly = goals.reduce((acc: number, goal: FinancialGoal) => acc + calculateGap(goal), 0);

  return (
    <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-8 w-full">
      <div className="flex flex-wrap justify-between items-end gap-4 px-1 mb-8">
        <div className="flex flex-col gap-2">
          <h1 className="text-slate-900 dark:text-white text-3xl sm:text-4xl font-black leading-tight tracking-[-0.033em]">Goals</h1>
          <p className="text-slate-500 dark:text-slate-400 text-base font-normal max-w-2xl">
            Track your progress towards your most critical financial milestones. You should be saving <span className="text-primary font-bold">₹{totalRequiredMonthly.toLocaleString(undefined, {maximumFractionDigits:0})}/mo</span> to meet all targets.
          </p>
        </div>
        <button 
          onClick={() => { setEditingGoal(null); setIsGoalModalOpen(true); }}
          className="flex items-center gap-2 bg-primary hover:bg-primary/90 text-white px-5 py-2.5 rounded-lg text-sm font-bold transition-all shadow-lg shadow-primary/25"
        >
          <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>add</span>
          <span>Goal</span>
        </button>
      </div>

      <div className="flex flex-col gap-6 mt-4">
        {goals.map((goal: FinancialGoal) => {
          const reqMonthly = calculateGap(goal);
          const percent = Math.min(100, (goal.currentAmount / goal.targetAmount) * 100).toFixed(1);

          return (
            <div key={goal.id} className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 p-6 shadow-sm">
              <div className="flex flex-col lg:flex-row gap-8">
                <div className="flex gap-4 min-w-[200px]">
                  <div className="size-12 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center shrink-0">
                    <span className="material-symbols-outlined text-primary text-2xl">flag</span>
                  </div>
                  <div className="flex flex-col">
                    <h3 className="text-slate-900 dark:text-white font-bold text-lg">{goal.name}</h3>
                    <p className="text-slate-500 dark:text-slate-400 text-sm">Target: {new Date(goal.targetDate).toLocaleDateString()}</p>
                    <div className="mt-2 inline-flex items-center gap-1 px-2 py-1 rounded bg-orange-100 dark:bg-orange-900/20 text-orange-700 dark:text-orange-400 text-xs font-bold w-fit">
                      <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>warning</span>
                      <span>Requires: ₹{reqMonthly.toLocaleString(undefined, {maximumFractionDigits:0})}/mo</span>
                    </div>
                  </div>
                </div>

                <div className="flex-1 flex flex-col justify-center gap-6">
                  <div className="flex flex-col gap-2">
                    <div className="flex justify-between items-end">
                      <div className="flex flex-col">
                        <span className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wider">Progress</span>
                        <span className="text-slate-900 dark:text-white font-bold text-xl">₹{goal.currentAmount.toLocaleString()} <span className="text-sm text-slate-400 font-normal">/ ₹{goal.targetAmount.toLocaleString()}</span></span>
                      </div>
                      <span className="text-primary font-bold text-xl">{percent}%</span>
                    </div>

                    <div className="relative h-4 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                      <div className="absolute h-full bg-primary rounded-full transition-all duration-1000" style={{ width: `${percent}%` }}></div>
                    </div>
                    <div className="flex justify-between text-xs mt-1">
                      <span className="text-slate-400">Started: {new Date(goal.startDate).toLocaleDateString()}</span>
                    </div>
                  </div>
                </div>

                <div className="flex flex-col justify-center items-end min-w-[120px] border-l border-slate-100 dark:border-slate-700 pl-4 lg:pl-8">
                  <button className="w-full py-2 px-4 rounded-lg bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 text-slate-900 dark:text-white text-sm font-semibold transition-colors mb-2">
                      Top Up
                  </button>
                  <button 
                    onClick={() => { setEditingGoal(goal); setIsGoalModalOpen(true); }}
                    className="w-full py-2 px-4 rounded-lg text-primary hover:bg-primary/10 text-sm font-semibold transition-colors"
                  >
                      Edit Details
                  </button>
                </div>
              </div>
            </div>
          )
        })}
      </div>

      <EditGoalModal 
        isOpen={isGoalModalOpen}
        onClose={() => setIsGoalModalOpen(false)}
        editingGoal={editingGoal}
        onSave={(id, data) => {
          if (id) {
            const existing = goals.find((g: FinancialGoal) => g.id === id);
            if (existing) {
              dispatch(updateGoal({ ...existing, ...data }));
            }
          } else {
            dispatch(addGoal({
              id: `goal-${Date.now()}`,
              userId: "user-1",
              name: data.name,
              targetAmount: data.targetAmount,
              currentAmount: 0,
              targetDate: data.targetDate,
              startDate: new Date().toISOString(),
              category: "General"
            }));
          }
          setIsGoalModalOpen(false);
        }}
      />
    </div>
  );
}

